import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { useNavigate } from "react-router-dom";

export default function UserProfile() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [userProfile, setUserProfile] = useState(null);
  const [projects, setProjects] = useState([]);
  const [currentUser, setCurrentUser] = useState(null);

  useEffect(() => {
    init();
  }, [id]);

  const init = async () => {
    const { data } = await supabase.auth.getUser();
    const user = data.user;

    setCurrentUser(user);

    fetchUser();
    fetchProjects();
  };

  // 🔥 fetch user
  const fetchUser = async () => {
    const { data } = await supabase
      .from("profiles")
      .select("*")
      .eq("id", id)
      .single();

    setUserProfile(data);
  };

  // 🔥 fetch projects
  const fetchProjects = async () => {
    const { data } = await supabase
      .from("projects")
      .select("*")
      .eq("user_id", id)
      .order("created_at", { ascending: false });

    setProjects(data || []);
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>{userProfile?.name || "User"}</h2>

      <h3 style={{ marginTop: "20px" }}>Projects</h3>

      {projects.length === 0 ? (
        <p>No projects yet</p>
      ) : (
        projects.map((project) => (
          <ProjectCard
            key={project.id}
            project={project}
            currentUser={currentUser}
            navigate={navigate}
          />
        ))
      )}
    </div>
  );
}

// 🔥 Separate component for each project
function ProjectCard({ project, currentUser, navigate }) {
  const [following, setFollowing] = useState(false);

  useEffect(() => {
    if (currentUser) checkFollow();
  }, [currentUser]);

  const checkFollow = async () => {
    const { data } = await supabase
      .from("project_followers")
      .select("*")
      .eq("user_id", currentUser.id)
      .eq("project_id", project.id);

    setFollowing(data?.length > 0);
  };

  const handleFollow = async () => {
    if (!currentUser) return;

    if (following) {
      await supabase
        .from("project_followers")
        .delete()
        .eq("user_id", currentUser.id)
        .eq("project_id", project.id);

      setFollowing(false);
    } else {
      await supabase.from("project_followers").insert([
        {
          user_id: currentUser.id,
          project_id: project.id,
        },
      ]);

      setFollowing(true);
    }
  };

  return (
    <div
      style={{
        border: "1px solid gray",
        padding: "10px",
        marginTop: "10px",
        borderRadius: "8px",
      }}
    >
      <h4
        onClick={() => navigate(`/project/${project.id}`)}
        style={{ cursor: "pointer" }}
      >
        🚀 {project.title}
      </h4>

      <p>{project.description}</p>

      <button onClick={handleFollow}>
        {following ? "Unfollow" : "Follow Project"}
      </button>
    </div>
  );
}
